SET transaction_timeout = 0;
SET check_function_bodies = false;

-- Six private labels for the test user, plus 25 journal entries spanning
-- the same training window as the seeded sessions and weigh-ins. Stable
-- UUIDs so re-runs are idempotent and the join table can reference them.

ON CONFLICT (user_id, name) DO NOTHING;

    E'First weigh-in. **83.2 kg** — heavier than I''d like, but a clean baseline.\n\nPlan for the next ~12 weeks:\n- 500 kcal deficit, ~180 g protein\n- 4 lifts/week (push / legs / pull / full-body)\n- One walk-only rest day\n\nGoal: get under 80 kg without losing strength.'),
  ('bbbbbbbb-2222-2222-2222-222222222202', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-09-11', NULL,
    E'First week was harder than expected. Energy dipped Wed–Thu, evened out by Sunday''s session. Bench felt heavy at 70 kg — usually that''s smooth. Three sessions in. Trust the process.'),
  ('bbbbbbbb-2222-2222-2222-222222222203', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-09-25', 'Hitting my stride',
    E'Down to 81.6 kg already. The push days are clicking — incline DB went up to **22 kg per side** for 8s. Holding intensity through the cut: easier than I thought, as long as sleep is on point.'),
  ('bbbbbbbb-2222-2222-2222-222222222204', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-10-02', 'Energy is up',
    E'Three weeks in and the morning crash is gone. Carb-cycling around training days has been a game changer. Lower carbs Mon/Wed, higher carbs the rest. Keep this.'),
  ('bbbbbbbb-2222-2222-2222-222222222205', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-10-16', 'Sleep matters',
    E'Tracked sleep this week. **7h22m average**, down from ~8h before. Friday''s session was the worst — 60 kg bench felt like 80 kg. Putting the phone in another room from now on.'),
  ('bbbbbbbb-2222-2222-2222-222222222206', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-10-23', NULL,
    E'Squat PR: **110 kg × 5**. Mid-cut, which makes it sweeter. Knees moved well. Loving this.'),
  ('bbbbbbbb-2222-2222-2222-222222222207', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-11-06', 'First month down',
    E'Halfway-ish to the goal. Down ~5 kg, lifts trending up. Some thoughts:\n\n1. Protein at 180 g/day made the deficit painless.\n2. Two-a-days don''t help — they wreck recovery.\n3. Walking after meals: underrated.'),
  ('bbbbbbbb-2222-2222-2222-222222222208', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-11-20', NULL,
    E'Energy dipped this week, mood with it. Probably too aggressive on calories. Bumping up by 200 next week and seeing.'),
  ('bbbbbbbb-2222-2222-2222-222222222209', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-11-27', 'Thanksgiving thoughts',
    E'Ate freely today and don''t feel bad about it. One big meal isn''t going to undo a quarter of work. Back to plan tomorrow.'),
  ('bbbbbbbb-2222-2222-2222-222222222210', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-12-04', 'Sticking with it',
    E'77 kg at the gym this morning. Vest on for pull-ups, **+10 kg, 3×5**. The first one was clean, the others ugly. Worth it.'),
  ('bbbbbbbb-2222-2222-2222-222222222211', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-12-18', 'Deload week',
    E'Lifts down to ~60% volume this week. Long walks, more sleep, more cooking at home. Body feels grateful — joints stopped complaining.'),
  ('bbbbbbbb-2222-2222-2222-222222222212', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2025-12-25', 'Christmas day',
    E'Off day. Family. Wine. Cake.\n\nBest lift today: my nephew, who''s 4.'),
  ('bbbbbbbb-2222-2222-2222-222222222213', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-01-02', 'New year, new lifts',
    E'Came back from the holiday +0.6 kg, exactly as planned. Now: keep grinding. Programmed a 6-week strength block — bench, squat, deadlift, OHP. Same accessories.'),
  ('bbbbbbbb-2222-2222-2222-222222222214', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-01-09', 'Back at it',
    E'Bench felt strong: **80 kg × 3**, fast bar speed. Diet back on rails — meal-prepped Sunday for 4 days. Coffee at 5:30, lift at 6:00, work at 8:30. The rhythm is back.'),
  ('bbbbbbbb-2222-2222-2222-222222222215', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-01-23', NULL,
    E'Couldn''t sleep last night. Mind wouldn''t stop. Skipped morning lift, slept till 8. No guilt — recovery is training too.'),
  ('bbbbbbbb-2222-2222-2222-222222222216', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-01-30', 'Five months in',
    E'- Weight: **75.6 kg** (started 83.2)\n- Bench: 85 kg (was 75)\n- Squat: 120 kg (was 105)\n- Sleep: solid most nights\n\nThe grind is paying off. One more month of cutting, then transition.'),
  ('bbbbbbbb-2222-2222-2222-222222222217', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-02-13', 'Lean bulk begins',
    E'Adding 300 kcal back. Goal: **+1 kg/month** while keeping body fat under control. Training shifts to hypertrophy emphasis — more volume, slightly less intensity. Excited for the change.'),
  ('bbbbbbbb-2222-2222-2222-222222222218', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-02-27', NULL,
    E'Sleep''s been incredible this week. 8h+ every night. Lifts feel like the bar is lighter. Sleep > everything.'),
  ('bbbbbbbb-2222-2222-2222-222222222219', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-03-06', 'Calories up, body still tight',
    E'Two weeks of +300 kcal and the scale moved up 0.6 kg without any visible softness. Curious how long this magic will last. Until then: enjoy.'),
  ('bbbbbbbb-2222-2222-2222-222222222220', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-03-20', 'Bench PR!',
    E'**90 kg × 3.** First triple ever at this weight. Spotter told me to grind out a 4th — wisely declined. Next session will get it.'),
  ('bbbbbbbb-2222-2222-2222-222222222221', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-04-03', 'Recovery is the secret',
    E'Had a stretch where I felt unstoppable. Then ignored the warning signs (stiff hips, low motivation) and tweaked my lower back. One day off would have prevented three. Lesson burnt in.'),
  ('bbbbbbbb-2222-2222-2222-222222222222', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-04-17', 'Vacation prep',
    E'10 days in Lisbon coming up. Plan:\n- Two bodyweight sessions/week\n- Walk ≥10k steps daily\n- Eat what looks good, just stop when full\n\nNot aiming for a vacation PR, aiming to enjoy.'),
  ('bbbbbbbb-2222-2222-2222-222222222223', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-04-24', 'Stress week',
    E'Project crunch at work. Lifts: skipped two, kept one. Sleep: bad. Mood: meh. The body and mind are loud — listening for a change.'),
  ('bbbbbbbb-2222-2222-2222-222222222224', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-05-01', E'Summer''s almost here',
    E'Last weigh-in: 78.5 kg, 14.2% body fat. Frame holds the weight better than it did at 83. Plan for May: maintain calories, push the strength block one more cycle, then a small reverse diet.'),
  ('bbbbbbbb-2222-2222-2222-222222222225', 'f26ac88d-4dcd-48e8-a0ae-b4248918bc1c', '2026-05-08', '8 months reflection',
    E'What I learned across the cut + bulk:\n\n1. **Sleep is the multiplier.** Everything else falls apart without it.\n2. **Protein > everything else macro-wise.** Filling, recovery, lean-mass insurance.\n3. **Walking is underrated.** 10k+ steps/day fixed more than any "fat burner" ever did.\n4. **Slow is fast.** 0.5 kg/week up or down — sustainable. Faster wrecks the experience.\n\nOnto the next chapter.')
ON CONFLICT (id) DO NOTHING;

